// ─── LogosSection ─────────────────────────────────────────────────────────────
//
// Replicates the FeedSpring "3,500+ businesses" social proof section:
//   - Centered paragraph headline
//   - Horizontal infinite-scroll carousel (CSS animation, no JS)
//   - Edge fade via mask-image gradient (left + right transparency)
//   - Logos duplicated so the loop is seamless
//
// Background: transparent — inherits the gradient wrapper from LandingPage.
// ──────────────────────────────────────────────────────────────────────────────

import { motion } from "framer-motion";

// ─── Easing ───────────────────────────────────────────────────────────────────
const EASE = [0.22, 1, 0.36, 1] as const;

// ─── CSS keyframe injected once ───────────────────────────────────────────────
// We inject a <style> tag so we don't need a global CSS file.
// The animation shifts the track leftward by exactly 50% (half of the
// duplicated content), creating a perfectly seamless loop.
const KEYFRAMES = `
@keyframes vida-scroll-left {
  0%   { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}
`;

// ─── Logo SVGs ────────────────────────────────────────────────────────────────
// Extracted from the reference HTML — all logos use fill="#26262E" (near-black).
// They are intentionally muted on the blue gradient via opacity.

