// ─── Logo set — one pass ──────────────────────────────────────────────────────
// Four logos per pass; the track is duplicated in JSX for seamless loop.
const LOGOS = [
  { id: "framer", el: <LogoFramer /> },
  { id: "quincy", el: <LogoQuincy /> },
  { id: "backpocket", el: <LogoBackpocket /> },
  { id: "logitech", el: <LogoLogitech /> },
];

// ─── LogosSection ─────────────────────────────────────────────────────────────
export function LogosSection() {
  return (
    <section className="relative w-full pt-16 pb-20">
      {/* Inject keyframes */}
      <style>{KEYFRAMES}</style>

      {/* ── Headline ────────────────────────────────────────────────────── */}
      <motion.p
        initial={{ opacity: 0, y: 12 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6, ease: EASE, delay: 0.1 }}
        className="text-center font-medium mb-10"
        style={{
          fontSize: "15px",
          color: "#050414",
          letterSpacing: "-0.01em",
        }}
      >
        3,500+ businesses turn social proof into sales.
      </motion.p>

      {/* ── Carousel track ──────────────────────────────────────────────── */}
      {/*
       * Centering strategy:
       *   - Outer wrapper: max-width + mx-auto limits the visual band
       *     to the center of the screen, leaving empty space on both sides.
       *   - The masked overflow div sits inside, so the fade operates
       *     within the centered band, not from the screen edge.
       *   - mask-image fade: 12% transparent zone on each side so logos
       *     dissolve softly rather than cutting abruptly.
       */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.8, ease: EASE, delay: 0.2 }}
        style={{
          maxWidth: "900px",
          margin: "0 auto",
          padding: "0 40px",
        }}
      >
        {/* Masked overflow container — fade applied here, within the centered band */}
        <div
          style={{
            overflow: "hidden",
            maskImage:
              "linear-gradient(to right, transparent 0%, black 15%, black 85%, transparent 100%)",
            WebkitMaskImage:
              "linear-gradient(to right, transparent 0%, black 15%, black 85%, transparent 100%)",
          }}
        >
          {/* Scrolling track — two identical passes for seamless loop */}
          <div
            style={{
              display: "flex",
              width: "max-content",
              animation: "vida-scroll-left 20000ms linear infinite",
              willChange: "transform",
            }}
          >
            {/* Pass 1 */}
            {LOGOS.map(({ id, el }) => (
              <div
                key={`a-${id}`}
                style={{
                  flexShrink: 0,
                  flexGrow: 0,
                  padding: "0 48px",
                  display: "flex",
                  alignItems: "center",
                  color: "#050414",
                }}
              >
                {el}
              </div>
            ))}

            {/* Pass 2 — duplicate for seamless loop */}
            {LOGOS.map(({ id, el }) => (
              <div
                key={`b-${id}`}
                aria-hidden="true"
                style={{
                  flexShrink: 0,
                  flexGrow: 0,
                  padding: "0 48px",
                  display: "flex",
                  alignItems: "center",
                  color: "#050414",
                }}
              >
                {el}
              </div>
            ))}
          </div>
        </div>
      </motion.div>
    </section>
  );
}
